import React, { useState } from 'react'
import FullCalendar from '@fullcalendar/react'
import dayGridPlugin from '@fullcalendar/daygrid'
import timeGridPlugin from '@fullcalendar/timegrid'
import interactionPlugin from '@fullcalendar/interaction'
import {
  CCard,
  CCardBody,
  CCardHeader,
} from '@coreui/react-pro'
import AppointmentsC from '../appointments/Appointments'
import { settingsAppointments, settingsUnavailabilities } from 'src/services/standardUsers'
import AddEventModal from './AddAppointements'
import AppointmentsView from '../appointments/Appointments.view'
import { CRow, CCol } from '@coreui/react'
import i18n from 'src/i18n'
const FullCalendarPlugin = () => {
  const [weekendsVisible, /* setWeekendsVisible */] = useState(true)
  const [currentEvents, setCurrentEvents] = useState([])
  const [viewDates, setViewDates] = useState({ start: null, end: null })

  const [showModal, setShowModal] = useState(false)
  const [newEventInfo, setNewEventInfo] = useState({
    title: '',
    startStr: '',
    endStr: '',
    allDay: false,
    calendar: null,
  })

  const [List, setList] = useState([])
  const [ListUnivailbe, setListUnivailbe] = useState([]);

  const fetchUnavailabilities = async () => {
    try {
      const list = await settingsUnavailabilities.getunavailabilities();
      if (list) {
        console.log('Unavailabilities list:', )
        setListUnivailbe(
          list.data[0].activeDays.map((item, index) => {
            const startDateTime = new Date(`${item.date}T${item.start_time}`)
            const endDateTime = new Date(`${item.date}T${item.end_time}`)
           console.log('Unavailability item:', item, startDateTime, endDateTime)
            // Cas spécial : si l'heure de fin est avant l'heure de début, on suppose que ça dépasse minuit
            if (endDateTime <= startDateTime) {
              endDateTime.setDate(endDateTime.getDate() + 1)
            }
             console.log({
              id: `unavail-${index}`, // ou item.id si dispo
              title: 'Indisponible',
              start: startDateTime.toISOString(),
              end: endDateTime.toISOString(),
              allDay: true,
              display: 'background',
              color: '#FFAAFF',
              extendedProps: {
                userId: item.userId,
                reason: 'Unavailability',
                start_time: item.start_time,
                end_time: item.end_time,
                date: item.date,
              },
            })
            return {
              id: `unavail-${index}`, // ou item.id si dispo
              title: 'Indisponible',
              start: startDateTime.toISOString(),
              end: endDateTime.toISOString(),
              allDay: true,
              display: 'background',
              color: '#d8d8d8',
              extendedProps: {
                userId: item.userId,
                reason: 'Unavailability',
                start_time: item.start_time,
                end_time: item.end_time,
                date: item.date,
              },
            }
          })
        )



        // setListUnivailbe(list?.data)
        // setListUnivailbe(list?.data?.map((item) => {
        //   const jours = []
        //   if (item.monday) jours.push('Lundi')
        //   if (item.tuesday) jours.push('Mardi')
        //   if (item.wednesday) jours.push('Mercredi')
        //   if (item.thursday) jours.push('Jeudi')
        //   if (item.friday) jours.push('Vendredi')
        //   if (item.saturday) jours.push('Samedi')
        //   if (item.sunday) jours.push('Dimanche')

        //   return {
        //     id: item.id,
        //     start: item.start_date,
        //     end: item.end_date,
        //     display: 'background',
        //     color: '#FFAAFF', // gris clair
        //     allDay: true,
        //     title: `Indisponible de ${item.start_time} à ${item.end_time} (${jours.join(', ')})`,
        //   }
        // }));
      }
    } catch (error) {
      console.error('Error fetching admin list:', error);
    }
  };



  const handleDateSelect = (selectInfo) => {
    setNewEventInfo({
      title: '',
      startStr: selectInfo.startStr,
      endStr: selectInfo.endStr,
      allDay: selectInfo.allDay,
      calendar: selectInfo.view.calendar,
    })
    selectInfo.view.calendar.unselect()
    setShowModal(true)
  }

  const handleEventClick = (clickInfo) => {
    if (window.confirm(`Supprimer le rendez-vous : '${clickInfo.event.title}' ?`)) {
      clickInfo.event.remove()
    }
  }

  const handleEvents = (events) => {
    console.log('Events:', events)
    setCurrentEvents(events)
    console.log('Current events:', currentEvents)
  }

  const handleSaveEvent = () => {
    console.log('Saving event:', newEventInfo)
    if (newEventInfo.title && newEventInfo.calendar) {
      newEventInfo.calendar.addEvent({
        id: "createEventId(",
        title: newEventInfo.title,
        start: newEventInfo.startStr,
        end: newEventInfo.endStr,
        allDay: newEventInfo.allDay,
      })
    }
    setShowModal(false)
    setNewEventInfo({ title: '', startStr: '', endStr: '', allDay: false, calendar: null })
  }

  const handleDatesSet = (arg) => {
    setViewDates({
      start: arg.startStr,
      end: arg.endStr,
    })
    fetchAppointments({
      start: arg.startStr,
      end: arg.endStr,
    })
  }

  const fetchAppointments = async (data) => {
    try {
      fetchUnavailabilities();

      const list = await settingsAppointments.getAppointmentsFilter(data)
      if (list && list.data) {
        const formattedEvents = list.data.map((item) => {
          const startDate = new Date(item.date)
          const [hours, minutes] = item.time.split(':')
          startDate.setHours(+hours, +minutes, 0)
          const endDate = new Date(startDate.getTime() + item.duration * 60000)
          return {
            id: item.id,
            title: item.client_name || 'Rendez-vous',
            start: startDate.toISOString(),
            end: endDate.toISOString(),
            allDay: true,
            extendedProps: {
              client_code: item.client_code,
              client_contact: item.client_contact,
              meeting_reason: item.meeting_reason,
              hardware: item.hardware,
              software: item.software,
              status: item.status,
              description: item.description,
            },
          }
        })

        setList(formattedEvents)
        console.log('Formatted events:', formattedEvents)
      }
    } catch (error) {
      console.error('Error fetching appointments:', error)
    }
  }

  return (
    <CCard className="mb-4">
      <CCardHeader>

        <CRow className="align-items-center">
          <CCol md="6" xs="12">
            <strong>   {i18n.t('Calendrier des Rendez-vous')}</strong>
          </CCol>
          <CCol md="6" xs="12" className="text-md-end mt-md-0 mt-3">
            <AppointmentsC refresh={() => fetchAppointments(viewDates)} />
            <AddEventModal
              visible={showModal}
              onClose={() => setShowModal(false)}
              onSave={handleSaveEvent}
              title={newEventInfo.title}
              setTitle={(value) => setNewEventInfo({ ...newEventInfo, title: value })}
            />
          </CCol>

        </CRow>
      </CCardHeader>
      {viewDates.start && viewDates.end && (
        <div className="mt-3 px-4">
          <strong>Période affichée :</strong><br />
          Du <b>{viewDates.start}</b> au <b>{viewDates.end}</b>
        </div>
      )}

      <CCardBody>
        <FullCalendar
          plugins={[dayGridPlugin, timeGridPlugin, interactionPlugin]}
          headerToolbar={{
            left: 'prev,next today',
            center: 'title',
            right: 'dayGridMonth,timeGridWeek,timeGridDay',
          }}
          initialView="dayGridMonth"
          editable={true}
          selectable={true}
          selectMirror={true}
          dayMaxEvents={true}
          weekends={weekendsVisible}
          select={handleDateSelect}
          eventContent={renderEventContent}
          eventClick={handleEventClick}
          eventsSet={handleEvents}
          datesSet={handleDatesSet}
          events={[...List, ...ListUnivailbe]}
        />


      </CCardBody>
    </CCard>
  )
}

const renderEventContent = (eventInfo) => {
  console.log("renderEventContent", eventInfo.event)
  return (
    <div>

      <b>{eventInfo.timeText}</b> — <span>{eventInfo.event.title}</span>
      <br />
      <small>{eventInfo.event.extendedProps.meeting_reason}</small>
      <AppointmentsView selectedAppointments={eventInfo} />

    </div>
  )
}

export default FullCalendarPlugin
