import React, { useState } from 'react';
import {
  CButton,
  CModal,
  CModalHeader,
  CModalTitle,
  CModalBody,
  CRow,
  CCol,
  CFormLabel,
} from '@coreui/react';
import CIcon from '@coreui/icons-react';
import {  cilVector } from '@coreui/icons';
import PropTypes from 'prop-types';

const AppointmentsView = ({ refresh, selectedAppointments }) => {
  const [visible, setVisible] = useState(false);
  const event = selectedAppointments?.event;

  const formatDateTime = (dateStr) => {
    return new Date(dateStr).toLocaleString();
  };

  return (
    <>
      <CButton style={{backgroundColor:"#f096f9"}} onClick={() => setVisible(true)}>
        <CIcon icon={cilVector} />
      </CButton>

      <CModal alignment="center" visible={visible} onClose={() => setVisible(false)} size="lg">
        <CModalHeader onClose={() => setVisible(false)}>
          <CModalTitle>Détails du Rendez-vous</CModalTitle>
        </CModalHeader>
        <CModalBody>
          {event ? (
            <>
              <CRow className="mb-2">
                <CCol sm="4">
                  <CFormLabel>Nom du client :</CFormLabel>
                </CCol>
                <CCol>{event.title}</CCol>
              </CRow>
              <CRow className="mb-2">
                <CCol sm="4">
                  <CFormLabel>Code client :</CFormLabel>
                </CCol>
                <CCol>{event.extendedProps.client_code}</CCol>
              </CRow>
              <CRow className="mb-2">
                <CCol sm="4">
                  <CFormLabel>Contact client :</CFormLabel>
                </CCol>
                <CCol>{event.extendedProps.client_contact}</CCol>
              </CRow>
              <CRow className="mb-2">
                <CCol sm="4">
                  <CFormLabel>Raison :</CFormLabel>
                </CCol>
                <CCol>{event.extendedProps.meeting_reason}</CCol>
              </CRow>
              <CRow className="mb-2">
                <CCol sm="4">
                  <CFormLabel>Matériel :</CFormLabel>
                </CCol>
                <CCol>{event.extendedProps.hardware}</CCol>
              </CRow>
              <CRow className="mb-2">
                <CCol sm="4">
                  <CFormLabel>Logiciel :</CFormLabel>
                </CCol>
                <CCol>{event.extendedProps.software}</CCol>
              </CRow>
              <CRow className="mb-2">
                <CCol sm="4">
                  <CFormLabel>Date de début :</CFormLabel>
                </CCol>
                <CCol>{formatDateTime(event.start)}</CCol>
              </CRow>
              <CRow className="mb-2">
                <CCol sm="4">
                  <CFormLabel>Date de fin :</CFormLabel>
                </CCol>
                <CCol>{formatDateTime(event.end)}</CCol>
              </CRow>
              <CRow className="mb-2">
                <CCol sm="4">
                  <CFormLabel>Statut :</CFormLabel>
                </CCol>
                <CCol>{event.extendedProps.status}</CCol>
              </CRow>
              <CRow className="mb-2">
                <CCol sm="4">
                  <CFormLabel>Description :</CFormLabel>
                </CCol>
                <CCol>{event.extendedProps.description}</CCol>
              </CRow>
            </>
          ) : (
            <p>Aucune information de rendez-vous sélectionnée.</p>
          )}
        </CModalBody>
      </CModal>
    </>
  );
};

AppointmentsView.propTypes = {
  refresh: PropTypes.func.isRequired,
  selectedAppointments: PropTypes.object,
};

export default AppointmentsView;
